import psycopg2
from getpass import getpass

def install_extension(conn, extension_name):
    try:
        cur = conn.cursor()
        cur.execute("CREATE EXTENSION IF NOT EXISTS {}".format(extension_name))
        conn.commit()
        print(f"Extension {extension_name} installed successfully.")
    except Exception as e:
        print(f"Error installing extension {extension_name}: {str(e)}")

def main():
    # Get database connection details
    db_host = input("Enter database host: ")
    db_port = int(input("Enter database port: "))
    db_username = input("Enter database username: ")
    db_password = getpass("Enter database password: ")
    db_name = input("Enter database name: ")

    try:
        # Establish database connection
        conn = psycopg2.connect(
            host=db_host,
            port=db_port,
            user=db_username,
            password=db_password,
            dbname=db_name
        )
        
        while True:
            extension_name = input("Enter extension name to install (or 'exit' to quit): ")
            if extension_name.lower() == "exit":
                break
            install_extension(conn, extension_name)
    except Exception as e:
        print(f"Error connecting to database: {str(e)}")
    finally:
        if conn:
            conn.close()

if __name__ == "__main__":
    main()